  // ── Public API ────────────────────────────────────────────

  return {
    getDomains() { return DOMAINS; },
    getDomain(id) { return DOMAINS.find(d => d.id === id) || null; },
    getAllWords() {
      const result = [];
      DOMAINS.forEach(d => {
        d.words.forEach(w => result.push({ ...w, domainId: d.id, domainName: d.nameID }));
      });
      return result;
    },
    getTotalCount() {
      return DOMAINS.reduce((sum, d) => sum + d.words.length, 0);
    },
    getWordById(id) {
      for (const d of DOMAINS) {
        const w = d.words.find(w => w.id === id);
        if (w) return { ...w, domainId: d.id, domainName: d.nameID };
      }
      return null;
    },
  };

